package com.court.assistant.pdf

import android.content.Context
import android.graphics.Bitmap
import android.graphics.pdf.PdfRenderer
import android.os.ParcelFileDescriptor
import com.google.mlkit.vision.common.InputImage
import com.google.mlkit.vision.text.TextRecognition
import com.google.mlkit.vision.text.chinese.ChineseTextRecognizerOptions
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlinx.coroutines.withContext
import java.io.File
import java.util.*
import kotlin.coroutines.resume

data class SubpoenaInfo(
    val caseNumber: String?,
    val courtName: String?,
    val hearingTime: Long?,
    val partyNames: String?,
    val location: String?
)

class PdfParser(private val context: Context) {

    /**
     * 提取PDF首页标题（前5个有意义的汉字）
     */
    suspend fun extractTitleFromFirstPage(filePath: String): String? = withContext(Dispatchers.IO) {
        val file = File(filePath)
        if (!file.exists()) return@withContext null

        try {
            // 先尝试 iText 提取第一页文字
            val iTextResult = extractFirstPageWithIText(filePath)
            if (!iTextResult.isNullOrBlank()) {
                val title = extractTitleFromText(iTextResult)
                if (title != null) return@withContext title
            }

            // 回退到 OCR 提取第一页
            val ocrResult = extractFirstPageWithOcr(filePath)
            if (!ocrResult.isNullOrBlank()) {
                return@withContext extractTitleFromText(ocrResult)
            }
            null
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    /**
     * 从文字中提取标题（取前5个有意义的汉字）
     */
    private fun extractTitleFromText(text: String): String? {
        // 移除空白字符，只保留汉字和常用符号
        val cleaned = text.replace(Regex("\\s+"), "")

        // 优先查找包含关键词的短语
        val keywordPatterns = listOf(
            "传票", "开庭", "通知书", "应诉", "出庭", "举证",
            "民事", "刑事", "行政", "执行"
        )

        for (keyword in keywordPatterns) {
            val match = Regex("([\\u4e00-\\u9fa5]{0,10}${keyword}[\\u4e00-\\u9fa5]{0,10})").find(cleaned)
            if (match != null) {
                val title = match.value.trim()
                if (title.length >= 3) {
                    return title.take(8)
                }
            }
        }

        // 如果没找到关键词，提取第一个较长的汉字序列
        val chineseMatch = Regex("[\\u4e00-\\u9fa5]{5,20}").find(cleaned)
        return chineseMatch?.value?.take(8)
    }

    /**
     * 用 iText 提取第一页文字
     */
    private fun extractFirstPageWithIText(filePath: String): String? {
        return try {
            val reader = com.itextpdf.kernel.pdf.PdfReader(filePath)
            val doc = com.itextpdf.kernel.pdf.PdfDocument(reader)
            val text = com.itextpdf.kernel.pdf.canvas.parser.PdfTextExtractor.getTextFromPage(doc.getPage(1))
            doc.close()
            text
        } catch (_: Exception) { null }
    }

    /**
     * 用 OCR 提取第一页文字
     */
    private suspend fun extractFirstPageWithOcr(filePath: String): String? {
        val file = File(filePath)
        if (!file.exists()) return null
        val fd = ParcelFileDescriptor.open(file, ParcelFileDescriptor.MODE_READ_ONLY)
        val renderer = PdfRenderer(fd)

        if (renderer.pageCount == 0) {
            renderer.close()
            fd.close()
            return null
        }

        val page = renderer.openPage(0)
        val bitmap = Bitmap.createBitmap(page.width * 2, page.height * 2, Bitmap.Config.ARGB_8888)
        page.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY)
        page.close()
        renderer.close()
        fd.close()

        val recognizer = TextRecognition.getClient(ChineseTextRecognizerOptions.Builder().build())
        return suspendCancellableCoroutine { cont ->
            val image = InputImage.fromBitmap(bitmap, 0)
            recognizer.process(image)
                .addOnSuccessListener { result ->
                    bitmap.recycle()
                    cont.resume(result.text)
                }
                .addOnFailureListener {
                    bitmap.recycle()
                    cont.resume(null)
                }
        }
    }

    suspend fun parseSubpoena(filePath: String): SubpoenaInfo? = withContext(Dispatchers.IO) {
        val text = extractText(filePath)
        if (text.isNullOrBlank()) return@withContext null
        parseSubpoenaText(text)
    }

    private suspend fun extractText(filePath: String): String? {
        // 先尝试 iText 提取
        val iTextResult = extractWithIText(filePath)
        if (!iTextResult.isNullOrBlank() && iTextResult.any { it.code > 0x4E00 }) {
            return iTextResult
        }
        // 回退到 OCR
        return extractWithOcr(filePath)
    }

    private fun extractWithIText(filePath: String): String? {
        return try {
            val reader = com.itextpdf.kernel.pdf.PdfReader(filePath)
            val doc = com.itextpdf.kernel.pdf.PdfDocument(reader)
            val sb = StringBuilder()
            for (i in 1..doc.numberOfPages) {
                val text = com.itextpdf.kernel.pdf.canvas.parser.PdfTextExtractor.getTextFromPage(doc.getPage(i))
                sb.appendLine(text)
            }
            doc.close()
            sb.toString()
        } catch (_: Exception) { null }
    }

    private suspend fun extractWithOcr(filePath: String): String? {
        val file = File(filePath)
        if (!file.exists()) return null
        val fd = ParcelFileDescriptor.open(file, ParcelFileDescriptor.MODE_READ_ONLY)
        val renderer = PdfRenderer(fd)
        val sb = StringBuilder()
        val recognizer = TextRecognition.getClient(ChineseTextRecognizerOptions.Builder().build())

        for (i in 0 until renderer.pageCount) {
            val page = renderer.openPage(i)
            val bitmap = Bitmap.createBitmap(page.width * 2, page.height * 2, Bitmap.Config.ARGB_8888)
            page.render(bitmap, null, null, PdfRenderer.Page.RENDER_MODE_FOR_DISPLAY)
            page.close()

            val text = suspendCancellableCoroutine<String?> { cont ->
                val image = InputImage.fromBitmap(bitmap, 0)
                recognizer.process(image)
                    .addOnSuccessListener { result -> cont.resume(result.text) }
                    .addOnFailureListener { cont.resume(null) }
            }
            if (text != null) sb.appendLine(text)
            bitmap.recycle()
        }
        renderer.close()
        fd.close()
        return sb.toString().takeIf { it.isNotBlank() }
    }

    private fun parseSubpoenaText(text: String): SubpoenaInfo {
        val caseNumber = Regex("[（(]\\d{4}[）)][^\\s，。]+号").find(text)?.value
        val courtName = Regex("(.+?法院)").find(text)?.groupValues?.get(1)

        // 提取当事人信息
        val partyNames = try {
            val defendant = Regex("被告[：:]?\\s*([^\\n，。]+)").find(text)?.groupValues?.get(1)
            val plaintiff = Regex("原告[：:]?\\s*([^\\n，。]+)").find(text)?.groupValues?.get(1)
            listOfNotNull(plaintiff, defendant).joinToString(" vs ")
        } catch (e: Exception) { null }

        // 更强大的地点提取，支持多种格式
        val locationPatterns = listOf(
            // "应到地点：XXX法庭"
            Regex("(?:应到地点|开庭地点|地[点址]|地点)[：:]?\\s*([^\\n\\r，。]+?)(?:\\n|，|。|$)"),
            // "第X法庭" or "X号法庭"
            Regex("([\\d零一二三四五六七八九十]+号法庭)"),
            // "XX法院XX法庭"
            Regex("(.+?法院[\\d零一二三四五六七八九十]*号?法庭)"),
            // "在XX开庭"
            Regex("在(.{2,10})[开庭|审理]"),
            // "地点：XXX"
            Regex("地点[：:]\\s*([^\\n\\r，。]+)")
        )

        val location = locationPatterns.firstNotNullOfOrNull { it.find(text)?.groupValues?.get(1) }?.trim()

        var hearingTime: Long? = null
        // 更灵活的时间匹配模式，支持多种格式
        val timePatterns = listOf(
            // 格式1: "2024年3月15日 9时30分" 或 "2024-03-15 09:30"
            Regex("(?:应到时间|开庭时间|定于|时间)[：:]?\\s*(\\d{4})[年-](\\d{1,2})[月-](\\d{1,2})[日]?\\s*(\\d{1,2})[时点:：](\\d{1,2})[分分]?"),
            // 格式2: "2024年3月15日上午9点"
            Regex("(\\d{4})[年-](\\d{1,2})[月-](\\d{1,2})[日]?\\s*(上午|下午|中午)?\\s*(\\d{1,2})[时点:：]"),
            // 格式3: "定于2024年3月15日9时30分"
            Regex("定于[：:]?\\s*(\\d{4})[年-](\\d{1,2})[月-](\\d{1,2})[日]?\\s*(\\d{1,2})[时点:：](\\d{1,2})[分分]?"),
            // 格式4: 直接的时间格式 "2024.03.15 09:30"
            Regex("(\\d{4})[./年](\\d{1,2})[./月](\\d{1,2})[./日]?\\s*(\\d{1,2})[:：时](\\d{1,2})")
        )

        for (pattern in timePatterns) {
            val timeMatch = pattern.find(text)
            if (timeMatch != null) {
                try {
                    val year = timeMatch.groupValues[1].toInt()
                    val month = timeMatch.groupValues[2].toInt() - 1
                    val day = timeMatch.groupValues[3].toInt()
                    var hour = timeMatch.groupValues[4].toInt()
                    val minute = if (timeMatch.groupValues.size > 5) {
                        timeMatch.groupValues[5].takeIf { it.isNotEmpty() }?.toInt() ?: 0
                    } else 0

                    // 处理上午/下午
                    val ampm = if (timeMatch.groupValues.size > 6) timeMatch.groupValues.getOrNull(6) else null
                    if (ampm == "下午" || ampm == "中午") {
                        if (hour < 12) hour += 12
                    }

                    val cal = Calendar.getInstance().apply {
                        set(year, month, day, hour, minute, 0)
                        set(Calendar.MILLISECOND, 0)
                    }
                    hearingTime = cal.timeInMillis
                    break
                } catch (e: Exception) {
                    // 继续尝试下一个模式
                    continue
                }
            }
        }

        return SubpoenaInfo(caseNumber, courtName, hearingTime, partyNames, location)
    }
}

package com.court.assistant.calendar

import android.content.ContentUris
import android.content.ContentValues
import android.content.Context
import android.net.Uri
import android.provider.CalendarContract
import androidx.core.content.FileProvider
import java.io.File
import java.util.*

/**
 * 日历附件数据类
 */
data class CalendarAttachment(
    val uri: String,           // 文件 URI
    val name: String,          // 文件名称
    val type: AttachmentType   // 附件类型
)

enum class AttachmentType {
    PDF_SUBPOENA,   // PDF 传票
    PDF_DOCUMENT,   // PDF 文书
    SMS_NOTICE,     // 短信通知文本
    SMS_FILE        // 短信通知文件
}

class CalendarSync(private val context: Context) {

    fun syncHearing(
        caseNumber: String,
        courtName: String?,
        hearingTime: Long,
        partyNames: String?,
        description: String? = null,
        attachments: List<CalendarAttachment> = emptyList()
    ): Long? {
        // 去重：检查是否已存在
        if (eventExists(caseNumber, hearingTime)) return null

        val calendarId = getOrCreateCalendarId() ?: return null
        val title = buildString {
            append("开庭 ")
            if (courtName != null) append("$courtName ")
            append(caseNumber)
        }

        // 构建描述，包含详细的附件信息
        val desc = buildString {
            // 格式化显示精确的开庭时间
            val timeFormat = java.text.SimpleDateFormat("yyyy年MM月dd日 HH:mm", java.util.Locale.CHINA)
            append("⏰ 开庭时间: ${timeFormat.format(Date(hearingTime))}\n")

            if (partyNames != null) append("当事人: $partyNames\n")
            append("案号: $caseNumber")
            if (description != null) append("\n$description")

            // 添加详细的附件信息
            if (attachments.isNotEmpty()) {
                append("\n\n━━━━━━━━━━━━━━━━━━━━━━")
                append("\n【文书附件清单】")
                append("\n━━━━━━━━━━━━━━━━━━━━━━")

                attachments.forEachIndexed { index, attachment ->
                    append("\n\n${index + 1}. ${attachment.name}")
                    append("\n   类型: ${when(attachment.type) {
                        AttachmentType.PDF_SUBPOENA -> "📋 PDF传票"
                        AttachmentType.PDF_DOCUMENT -> "📄 PDF文书"
                        AttachmentType.SMS_NOTICE -> "💬 短信通知"
                        AttachmentType.SMS_FILE -> "📱 短信记录"
                    }}")

                    // 添加文件路径信息（用于调试）
                    val fileName = attachment.name
                    if (fileName.contains("_短信通知_")) {
                        // 从文件名提取信息
                        val parts = fileName.split("_")
                        if (parts.size >= 3) {
                            val dateStr = parts.getOrNull(2)?.replace(".txt", "") ?: ""
                            if (dateStr.length >= 14) {
                                val year = dateStr.substring(0, 4)
                                val month = dateStr.substring(4, 6)
                                val day = dateStr.substring(6, 8)
                                val hour = dateStr.substring(8, 10)
                                val minute = dateStr.substring(10, 12)
                                append("\n   时间: ${year}-${month}-${day} ${hour}:${minute}")
                            }
                        }
                    }
                }

                append("\n\n━━━━━━━━━━━━━━━━━━━━━━")
                append("\n💡 提示: 打开【法院助手】应用可查看完整文书")
            }
        }

        val values = ContentValues().apply {
            put(CalendarContract.Events.CALENDAR_ID, calendarId)
            put(CalendarContract.Events.TITLE, title)
            put(CalendarContract.Events.DESCRIPTION, desc)
            put(CalendarContract.Events.DTSTART, hearingTime)
            put(CalendarContract.Events.DTEND, hearingTime + 2 * 3600 * 1000) // 2小时
            put(CalendarContract.Events.EVENT_TIMEZONE, TimeZone.getDefault().id)
            put(CalendarContract.Events.HAS_ALARM, 1)
        }

        val uri = context.contentResolver.insert(CalendarContract.Events.CONTENT_URI, values)
        val eventId = uri?.let { ContentUris.parseId(it) }

        // 添加提醒：提前1天和1小时
        if (eventId != null) {
            addReminder(eventId, 24 * 60) // 1天
            addReminder(eventId, 60)       // 1小时
        }
        return eventId
    }

    private fun eventExists(caseNumber: String, hearingTime: Long): Boolean {
        val projection = arrayOf(CalendarContract.Events._ID)
        val selection = "${CalendarContract.Events.TITLE} LIKE ? AND ${CalendarContract.Events.DTSTART} = ?"
        val args = arrayOf("%$caseNumber%", hearingTime.toString())
        val cursor = context.contentResolver.query(
            CalendarContract.Events.CONTENT_URI, projection, selection, args, null
        )
        val exists = cursor?.use { it.count > 0 } ?: false
        return exists
    }

    private fun getOrCreateCalendarId(): Long? {
        // 先查找已有日历
        val projection = arrayOf(CalendarContract.Calendars._ID)
        val cursor = context.contentResolver.query(
            CalendarContract.Calendars.CONTENT_URI, projection, null, null, null
        )
        cursor?.use {
            if (it.moveToFirst()) return it.getLong(0)
        }
        return null // 使用系统默认日历
    }

    private fun addReminder(eventId: Long, minutes: Int) {
        val values = ContentValues().apply {
            put(CalendarContract.Reminders.EVENT_ID, eventId)
            put(CalendarContract.Reminders.MINUTES, minutes)
            put(CalendarContract.Reminders.METHOD, CalendarContract.Reminders.METHOD_ALERT)
        }
        context.contentResolver.insert(CalendarContract.Reminders.CONTENT_URI, values)
    }

    /**
     * 创建附件 URI
     */
    fun createAttachmentUri(filePath: String): CalendarAttachment? {
        val file = File(filePath)
        if (!file.exists()) return null

        val uri: Uri = try {
            FileProvider.getUriForFile(
                context,
                "${context.packageName}.fileprovider",
                file
            )
        } catch (e: Exception) {
            return null
        }

        val fileName = file.name
        val type = when {
            fileName.contains("传票") || fileName.lowercase().contains("subpoena") -> AttachmentType.PDF_SUBPOENA
            fileName.endsWith(".pdf", ignoreCase = true) -> AttachmentType.PDF_DOCUMENT
            else -> AttachmentType.SMS_NOTICE
        }

        return CalendarAttachment(
            uri = uri.toString(),
            name = fileName,
            type = type
        )
    }

    /**
     * 为短信内容创建文本文件附件
     */
    fun createSmsAttachment(
        caseNumber: String,
        courtName: String?,
        body: String,
        receivedAt: Long
    ): CalendarAttachment? {
        return try {
            // 创建临时文件存储短信内容
            val dateFormat = java.text.SimpleDateFormat("yyyyMMdd_HHmmss", java.util.Locale.CHINA)
            val timestamp = dateFormat.format(java.util.Date(receivedAt))
            val fileName = "${caseNumber}_短信通知_$timestamp.txt"
            val file = File(context.getExternalFilesDir("SmsAttachments"), fileName)
            file.parentFile?.mkdirs()

            val content = buildString {
                appendLine("=" .repeat(50))
                appendLine("法院开庭短信通知")
                appendLine("=" .repeat(50))
                appendLine()
                appendLine("案号: $caseNumber")
                if (courtName != null) appendLine("法院: $courtName")
                appendLine("接收时间: ${java.text.SimpleDateFormat("yyyy-MM-dd HH:mm:ss", java.util.Locale.CHINA).format(java.util.Date(receivedAt))}")
                appendLine()
                appendLine("=" .repeat(50))
                appendLine("短信原文")
                appendLine("=" .repeat(50))
                appendLine(body)
                appendLine()
                appendLine("=" .repeat(50))
                appendLine("说明")
                appendLine("=" .repeat(50))
                appendLine("此短信由【法院助手】应用自动解析并同步到日历")
                appendLine("包含完整的案件信息和开庭时间")
            }

            file.writeText(content, Charsets.UTF_8)

            val uri: Uri = FileProvider.getUriForFile(
                context,
                "${context.packageName}.fileprovider",
                file
            )

            CalendarAttachment(
                uri = uri.toString(),
                name = fileName,
                type = AttachmentType.SMS_FILE
            )
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    /**
     * 删除已存在的日历事件（用于更新）
     */
    fun deleteEvent(caseNumber: String, hearingTime: Long): Boolean {
        val selection = "${CalendarContract.Events.TITLE} LIKE ? AND ${CalendarContract.Events.DTSTART} = ?"
        val args = arrayOf("%$caseNumber%", hearingTime.toString())
        val result = context.contentResolver.delete(
            CalendarContract.Events.CONTENT_URI,
            selection,
            args
        )
        return result > 0
    }
}

