    SMS_FILE        // 短信通知文件
}

class CalendarSync(private val context: Context) {

    fun syncHearing(
        caseNumber: String,
        courtName: String?,
        hearingTime: Long,
        partyNames: String?,
        description: String? = null,
        attachments: List<CalendarAttachment> = emptyList()
    ): Long? {
        // 去重：检查是否已存在
        if (eventExists(caseNumber, hearingTime)) return null

        val calendarId = getOrCreateCalendarId() ?: return null
        val title = buildString {
            append("开庭 ")
            if (courtName != null) append("$courtName ")
            append(caseNumber)
        }

        // 构建描述，包含详细的附件信息
        val desc = buildString {
            // 格式化显示精确的开庭时间
            val timeFormat = java.text.SimpleDateFormat("yyyy年MM月dd日 HH:mm", java.util.Locale.CHINA)
            append("⏰ 开庭时间: ${timeFormat.format(Date(hearingTime))}\n")

            if (partyNames != null) append("当事人: $partyNames\n")
            append("案号: $caseNumber")
            if (description != null) append("\n$description")

            // 添加详细的附件信息
            if (attachments.isNotEmpty()) {
                append("\n\n━━━━━━━━━━━━━━━━━━━━━━")
                append("\n【文书附件清单】")
                append("\n━━━━━━━━━━━━━━━━━━━━━━")

                attachments.forEachIndexed { index, attachment ->
                    append("\n\n${index + 1}. ${attachment.name}")
                    append("\n   类型: ${when(attachment.type) {
                        AttachmentType.PDF_SUBPOENA -> "📋 PDF传票"
                        AttachmentType.PDF_DOCUMENT -> "📄 PDF文书"
                        AttachmentType.SMS_NOTICE -> "💬 短信通知"
                        AttachmentType.SMS_FILE -> "📱 短信记录"
                    }}")

                    // 添加文件路径信息（用于调试）
                    val fileName = attachment.name
                    if (fileName.contains("_短信通知_")) {
                        // 从文件名提取信息
                        val parts = fileName.split("_")
                        if (parts.size >= 3) {
                            val dateStr = parts.getOrNull(2)?.replace(".txt", "") ?: ""
                            if (dateStr.length >= 14) {
                                val year = dateStr.substring(0, 4)
                                val month = dateStr.substring(4, 6)
                                val day = dateStr.substring(6, 8)
                                val hour = dateStr.substring(8, 10)
                                val minute = dateStr.substring(10, 12)
                                append("\n   时间: ${year}-${month}-${day} ${hour}:${minute}")
                            }
                        }
                    }
                }

                append("\n\n━━━━━━━━━━━━━━━━━━━━━━")
                append("\n💡 提示: 打开【法院助手】应用可查看完整文书")
            }
        }

        val values = ContentValues().apply {
            put(CalendarContract.Events.CALENDAR_ID, calendarId)
            put(CalendarContract.Events.TITLE, title)
            put(CalendarContract.Events.DESCRIPTION, desc)
            put(CalendarContract.Events.DTSTART, hearingTime)
            put(CalendarContract.Events.DTEND, hearingTime + 2 * 3600 * 1000) // 2小时
            put(CalendarContract.Events.EVENT_TIMEZONE, TimeZone.getDefault().id)
            put(CalendarContract.Events.HAS_ALARM, 1)
        }

        val uri = context.contentResolver.insert(CalendarContract.Events.CONTENT_URI, values)
        val eventId = uri?.let { ContentUris.parseId(it) }

        // 添加提醒：提前1天和1小时
        if (eventId != null) {
            addReminder(eventId, 24 * 60) // 1天
            addReminder(eventId, 60)       // 1小时
        }
        return eventId
    }

    private fun eventExists(caseNumber: String, hearingTime: Long): Boolean {
        val projection = arrayOf(CalendarContract.Events._ID)
        val selection = "${CalendarContract.Events.TITLE} LIKE ? AND ${CalendarContract.Events.DTSTART} = ?"
        val args = arrayOf("%$caseNumber%", hearingTime.toString())
        val cursor = context.contentResolver.query(
            CalendarContract.Events.CONTENT_URI, projection, selection, args, null
        )
        val exists = cursor?.use { it.count > 0 } ?: false
        return exists
    }

    private fun getOrCreateCalendarId(): Long? {
        // 先查找已有日历
        val projection = arrayOf(CalendarContract.Calendars._ID)
        val cursor = context.contentResolver.query(
            CalendarContract.Calendars.CONTENT_URI, projection, null, null, null
        )
        cursor?.use {
            if (it.moveToFirst()) return it.getLong(0)
        }
        return null // 使用系统默认日历
    }

    private fun addReminder(eventId: Long, minutes: Int) {
        val values = ContentValues().apply {
            put(CalendarContract.Reminders.EVENT_ID, eventId)
            put(CalendarContract.Reminders.MINUTES, minutes)
            put(CalendarContract.Reminders.METHOD, CalendarContract.Reminders.METHOD_ALERT)
        }
        context.contentResolver.insert(CalendarContract.Reminders.CONTENT_URI, values)
    }

    /**
     * 创建附件 URI
     */
    fun createAttachmentUri(filePath: String): CalendarAttachment? {
        val file = File(filePath)
        if (!file.exists()) return null

        val uri: Uri = try {
            FileProvider.getUriForFile(
                context,
                "${context.packageName}.fileprovider",
                file
            )
        } catch (e: Exception) {
            return null
        }

        val fileName = file.name
        val type = when {
            fileName.contains("传票") || fileName.lowercase().contains("subpoena") -> AttachmentType.PDF_SUBPOENA
            fileName.endsWith(".pdf", ignoreCase = true) -> AttachmentType.PDF_DOCUMENT
            else -> AttachmentType.SMS_NOTICE
        }

        return CalendarAttachment(
            uri = uri.toString(),
            name = fileName,
            type = type
        )
    }

    /**
     * 为短信内容创建文本文件附件
     */
    fun createSmsAttachment(
        caseNumber: String,
        courtName: String?,
        body: String,
        receivedAt: Long
    ): CalendarAttachment? {
        return try {
            // 创建临时文件存储短信内容
            val dateFormat = java.text.SimpleDateFormat("yyyyMMdd_HHmmss", java.util.Locale.CHINA)
            val timestamp = dateFormat.format(java.util.Date(receivedAt))
            val fileName = "${caseNumber}_短信通知_$timestamp.txt"
            val file = File(context.getExternalFilesDir("SmsAttachments"), fileName)
            file.parentFile?.mkdirs()

            val content = buildString {
                appendLine("=" .repeat(50))
                appendLine("法院开庭短信通知")
                appendLine("=" .repeat(50))
                appendLine()
                appendLine("案号: $caseNumber")
                if (courtName != null) appendLine("法院: $courtName")
                appendLine("接收时间: ${java.text.SimpleDateFormat("yyyy-MM-dd HH:mm:ss", java.util.Locale.CHINA).format(java.util.Date(receivedAt))}")
                appendLine()
                appendLine("=" .repeat(50))
                appendLine("短信原文")
                appendLine("=" .repeat(50))
                appendLine(body)
                appendLine()
                appendLine("=" .repeat(50))
                appendLine("说明")
                appendLine("=" .repeat(50))
                appendLine("此短信由【法院助手】应用自动解析并同步到日历")
                appendLine("包含完整的案件信息和开庭时间")
            }

            file.writeText(content, Charsets.UTF_8)

            val uri: Uri = FileProvider.getUriForFile(
                context,
                "${context.packageName}.fileprovider",
                file
            )

            CalendarAttachment(
                uri = uri.toString(),
                name = fileName,
                type = AttachmentType.SMS_FILE
            )
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    /**
     * 删除已存在的日历事件（用于更新）
     */
    fun deleteEvent(caseNumber: String, hearingTime: Long): Boolean {
        val selection = "${CalendarContract.Events.TITLE} LIKE ? AND ${CalendarContract.Events.DTSTART} = ?"
        val args = arrayOf("%$caseNumber%", hearingTime.toString())
        val result = context.contentResolver.delete(
            CalendarContract.Events.CONTENT_URI,
            selection,
            args
        )
        return result > 0
    }
}

