    suspend fun createZipForPdf(pdfIds: List<Long>): String? {
        return try {
            val zipDir = java.io.File(getApplication<Application>().getExternalFilesDir(null), "Zips")
            if (!zipDir.exists()) zipDir.mkdirs()

            val timestamp = java.text.SimpleDateFormat("yyyyMMdd_HHmmss", java.util.Locale.CHINA)
                .format(java.util.Date())
            val zipFile = java.io.File(zipDir, "法院文书_$timestamp.zip")

            java.util.zip.ZipOutputStream(java.io.FileOutputStream(zipFile)).use { zos ->
                pdfIds.forEach { pdfId ->
                    val pdf = repo.getPdfById(pdfId) ?: return@forEach
                    val pdfFile = java.io.File(pdf.filePath)
                    if (!pdfFile.exists()) return@forEach
                    val entry = java.util.zip.ZipEntry(pdf.fileName)
                    zos.putNextEntry(entry)
                    pdfFile.inputStream().use { input ->
                        input.copyTo(zos)
                    }
                    zos.closeEntry()
                }
            }
            zipFile.absolutePath
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    /**
     * 获取某个短信关联的所有PDF的ZIP压缩包
     * @param smsId 短信ID
     * @return ZIP文件路径，失败返回null
     */
    suspend fun createZipForSms(smsId: Long): String? {
        val smsWithPdfs = _uiState.value.smsWithPdfs.find { it.sms.id == smsId }
            ?: return null
        val pdfIds = smsWithPdfs.pdfs.map { it.id }
        return if (pdfIds.isNotEmpty()) {
            val caseNumber = smsWithPdfs.sms.caseNumber ?: "案件"
            val zipPath = createZipForPdf(pdfIds)
            // 重命名ZIP文件为OCR标题（优先）或案号
            zipPath?.let {
                val oldFile = java.io.File(it)
                val sms = _uiState.value.smsWithPdfs.find { it.sms.id == smsId }
                val displayName = sms?.pdfs.firstNotNull()?.ocrTitle
                    ?: sms?.pdfs.firstNotNull()?.fileName ?: "未知文件"
                        .substringBeforeLast(".", "")
                val newFile = java.io.File(oldFile.parentFile, displayName + ".zip")
                oldFile.renameTo(newFile)
                newFile.absolutePath
            }
        } else null
    }
