                timeMatch.groupValues[4].toInt(),
                timeMatch.groupValues[5].takeIf { it.isNotEmpty() }?.toInt() ?: 0, 0)
            set(Calendar.MILLISECOND, 0)
        }
        hearingTime = cal.timeInMillis
    }

