class CalendarSync(private val context: Context) {

    fun syncHearing(
        caseNumber: String,
        courtName: String?,
        hearingTime: Long,
        defendant: String?,        // 被传唤人
        handler: String?,          // 承办人
        location: String?,         // 应到处所
        phone: String?,            // 电话
        partyNames: String? = null,
        description: String? = null
    ): Long? {
        // 去重：检查是否已存在
        if (eventExists(caseNumber, hearingTime)) return null

        val calendarId = getOrCreateCalendarId() ?: return null
        val title = buildString {
            append("开庭 ")
            if (courtName != null) append("$courtName ")
            append(caseNumber)
        }
        val desc = buildString {
            // 格式化显示精确的开庭时间
            val timeFormat = java.text.SimpleDateFormat("yyyy年MM月dd日 HH:mm", java.util.Locale.CHINA)
            append("⏰ 开庭时间: ${timeFormat.format(java.util.Date(hearingTime))}\n")

            // 7个关键信息字段
            append("案号: $caseNumber")
            if (courtName != null) append("\n法院: $courtName")
            if (defendant != null) append("\n被传唤人: $defendant")
            if (handler != null) append("\n承办人: $handler")
            if (location != null) append("\n应到处所: $location")
            if (phone != null) append("\n电话: $phone")
            if (partyNames != null) append("\n当事人: $partyNames")
            if (description != null) append("\n$description")
        }

        val values = ContentValues().apply {
            put(CalendarContract.Events.CALENDAR_ID, calendarId)
            put(CalendarContract.Events.TITLE, title)
            put(CalendarContract.Events.DESCRIPTION, desc)
            put(CalendarContract.Events.DTSTART, hearingTime)
            put(CalendarContract.Events.DTEND, hearingTime + 2 * 3600 * 1000) // 2小时
            put(CalendarContract.Events.EVENT_TIMEZONE, TimeZone.getDefault().id)
            put(CalendarContract.Events.HAS_ALARM, 1)
        }

        val uri = context.contentResolver.insert(CalendarContract.Events.CONTENT_URI, values)
        val eventId = uri?.let { ContentUris.parseId(it) }

